SELECT SUM(generation_gwh) AS total_energy_generated
FROM energy_generation
WHERE year = 2023 AND fuel_type = 'Hydro' AND plant_id = 1;

SELECT plant_id, SUM(generation_gwh) AS total_power_generated
FROM energy_generation
GROUP BY plant_id;

SELECT COUNT(incident_id) 
FROM plant_incidents 
WHERE incident_status = 'Resolved';

SELECT *
FROM plants
ORDER BY plant_type, plant_name;

SELECT AVG(pe.efficiency_percentage) AS average_efficiency
FROM plant_efficiency pe
WHERE pe.month = 9 AND pe.year = 2023;

SELECT AVG(efficiency_percentage) AS average_efficiency
FROM plant_efficiency
WHERE year = 2003;

SELECT generation_id, plant_id, generation_gwh
FROM energy_generation
ORDER BY generation_gwh DESC;
